from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Initialize PassageManager to access index data
        passage_manager = PassageManager(index_path)

        # Extract metadata fields from all passages
        metadata_fields = set()
        field_value_counts = defaultdict(Counter)

        for passage in passage_manager.passage_sources[0].passages.values():
            # Collect unique field names
            metadata_fields.update(passage.metadata.keys())

            # Count occurrences of each field value
            for field_name, field_value in passage.metadata.items():
                field_value_counts[field_name][field_value] += 1

        return {
            "total_passages": len(passage_manager.passage_sources[0].passages),
            "metadata_fields": sorted(list(metadata_fields)),
            "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
        }

    except FileNotFoundError as e:
        # Re-raise with more specific message
        raise FileNotFoundError(f"Index metadata file not found at {index_path}") from e

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Initialize PassageManager to access index data
        passage_manager = PassageManager(index_path)
        total_passages = len(passage_manager.passage_sources[0].passages)

        if total_passages == 0:
            return {
                "coverage_percentage": 0.0,
                "field_coverage": {},
                "missing_fields": required_fields
            }

        # Check which required fields are missing from all passages
        all_fields = set()
        for passage in passage_manager.passage_sources[0].passages.values():
            all_fields.update(passage.metadata.keys())

        missing_fields = [field for field in required_fields if field not in all_fields]

        # Analyze coverage for each passage
        covered_passages = 0
        field_coverage = {}

        for field_name in required_fields:
            covered_count = 0

            for passage in passage_manager.passage_sources[0].passages.values():
                if field_name in passage.metadata:
                    covered_count += 1

            coverage_percentage = (covered_count / total_passages) * 100
            field_coverage[field_name] = round(coverage_percentage, 2)

            # Check if all required fields are present in a passage
            if coverage_percentage == 100.0:
                covered_passages += 1

        # Calculate overall coverage (only count passages that have ALL required fields)
        actual_covered = 0
        for passage in passage_manager.passage_sources[0].passages.values():
            has_all_fields = True
            for field in required_fields:
                if field not in passage.metadata:
                    has_all_fields = False
                    break
            if has_all_fields:
                actual_covered += 1

        overall_coverage = (actual_covered / total_passages) * 100 if total_passages > 0 else 0.0

        return {
            "coverage_percentage": round(overall_coverage, 2),
            "field_coverage": field_coverage,
            "missing_fields": missing_fields
        }

    except FileNotFoundError as e:
        # Re-raise with more specific message
        raise FileNotFoundError(f"Index metadata file not found at {index_path}") from e
